import type { Track, TrackGuide, TrackScore } from './tracks';

const businessReview = [
  'Approved by engineering review for deterministic business planning math',
  'Approved by scientific review for assumption framing and uncertainty language',
  'Approved for publication as educational business planning, not tax, legal, payroll, or accounting advice',
];

const businessMethodology = [
  'Calculator sequence before final verdict',
  'Decision checkpoints after each major step',
  'Ready, almost ready, fragile, and not ready result states',
  'Templates placed after the math so users can act on the result',
];

const businessMonetization = ['business banking', 'accounting software', 'payroll providers', 'CRM tools', 'SaaS management tools', 'professional review partners'];

const readyStates = [
  { range: '85-100', state: 'Ready', meaning: 'The numbers support the decision.' },
  { range: '70-84', state: 'Almost ready', meaning: 'The decision may work, but one or two assumptions need tightening.' },
  { range: '50-69', state: 'Fragile', meaning: 'The plan depends on optimistic assumptions.' },
  { range: '0-49', state: 'Not ready', meaning: 'Fix pricing, cash, role clarity, tax reserve, or revenue before acting.' },
];

const readinessVerdicts = [
  { state: 'Ready', verdict: 'The plan is supportable. Keep the cadence, protect the assumptions, and review the numbers when the business changes.' },
  { state: 'Almost ready', verdict: 'The plan is close, but one weak assumption needs attention before you rely on it.' },
  { state: 'Fragile', verdict: 'This can work only if too many things go right. Strengthen the weak assumption before spending or committing.' },
  { state: 'Not ready', verdict: 'This is not a failure. It means the business needs a stronger foundation before the decision becomes permanent.' },
];

function score(title: string, inputs: string[], summaryOutputs: string[]): TrackScore {
  return {
    title,
    inputs,
    states: readyStates,
    verdicts: readinessVerdicts,
    summaryOutputs,
  };
}

function guide(title: string, href: string): TrackGuide {
  return { title, href };
}

